[83] يُنظر: ((تفسير الجلالين)) (ص: 639)، ((تفسير العليمي)) (6/173)، ((تفسير الشوكاني)) (4/603)، ((تفسير ابن عاشور)) (25/35)، ((تفسير ابن عثيمين- سورة الشورى)) (ص: 54). ممَّن اختار المعنى المذكورَ: جلالُ الدِّين المحلِّي، والعُلَيمي، والشوكاني، وابن عاشور، وابن عثيمين. يُنظر المصادر السابقة. قال ابن عاشور: (والقولُ في وَكَذَلِكَ أَوْحَيْنَا كالقولِ في كَذَلِكَ يُوحِي إِلَيْكَ). ((تفسير ابن عاشور)) (25/35). وقيل: المعنى: ومِثلَ ذلك أوْحَيْنا إليكَ، و«ذلك» إشارةٌ إلى معنى الآيةِ قبْلَها: مِن أنَّ اللهَ تعالى هو الرَّقيبُ عليهم، وما أنت برقيبٍ عليهم، ولكنْ نذيرٌ لهم؛ لأنَّ هذا المعنى كرَّره اللهُ تعالى في كتابه في مواضعَ جمَّةٍ. ومِمَّن ذهب إلى هذا المعنى في الجملةِ: الزمخشريُّ، والرازي، وأبو حيَّان. يُنظر: ((تفسير الزمخشري)) (4/210)، ((تفسير الرازي)) (27/580)، ((تفسير أبي حيان)) (9/324). قال الرازي: (اعلَمْ أنَّ كلمةَ «ذلك» للإشارةِ إلى شَيءٍ سبَق ذِكرُه، فقولُه: وَكَذَلِكَ أَوْحَيْنَا إِلَيْكَ قُرْآَنًا عَرَبِيًّا يَقتضي تشبيهَ وحْيِ اللهِ بالقرآنِ بشَيءٍ هاهنا قد سبَق ذِكرُه، وليس هاهنا شَيءٌ سبَق ذِكرُه يُمكِنُ تشبيهُ وحْيِ القرآنِ به إلَّا قولَه وَالَّذِينَ اتَّخَذُوا مِنْ دُونِهِ أَولِيَاءَ اللَّهُ حَفِيظٌ عَلَيْهِمْ وَمَا أَنْتَ عَلَيْهِمْ بِوَكِيلٍ
[الشورى: 6]
). ((تفسير الرازي)) (27/580). قال القرطبي: (قَولُه تعالى: وَكَذَلِكَ أَوْحَيْنَا إِلَيْكَ قُرْآَنًا عَرَبِيًّا أي: وكما أوحَيْنا إليك وإلى مَن قَبْلَك هذه المعانيَ فكذلك أوحَيْنا إليك قُرآنًا عَربيًّا بَيَّنَّاه بلُغةِ العَرَبِ. وقيل: أي: أنزَلْنا عليك قرآنًا عربيًّا بلِسانِ قَومِك كما أرسَلْنا كُلَّ رسولٍ بلِسانِ قَومِه. والمعنى واحِدٌ). ((تفسير القرطبي)) (16/6).

[217] وممَّن ذهب إلى أنَّ معنى مِنْ بَعْدِهِمْ أي: مِن بَعدِ المختلِفينَ في الحقِّ: ابنُ جرير، ومكِّي ابن أبي طالب، والقرطبي، والبِقاعي، وابن عاشور. يُنظر: ((تفسير ابن جرير)) (20/484)، ((الهداية إلى بلوغ النهاية)) لمكي (10/6571)، ((تفسير القرطبي)) (16/12)، ((نظم الدرر)) للبقاعي (17/270)، ((تفسير ابن عاشور)) (25/59). قال ابن عاشور: (ضميرُ مِنْ بَعْدِهِمْ عائدٌ إلى ما عاد إليه ضميرُ تَفَرَّقُوا، وهم الَّذين خُوطِبوا بقولِه: وَلَا تَتَفَرَّقُوا فِيهِ
[الشورى: 13]
) . ((تفسير ابن عاشور)) (25/59). وقيل: معنى مِنْ بَعْدِهِمْ أي: مِن بَعدِ أنبيائِهم. وممَّن اختاره: مقاتلُ بنُ سُلَيمانَ، والبغويُّ، وابنُ الجوزي، والخازنُ. يُنظر: ((تفسير مقاتل بن سليمان)) (3/766)، ((تفسير البغوي)) (4/141)، ((تفسير ابن الجوزي)) (4/61)، ((تفسير الخازن)) (4/96). وقيل: مِنْ بَعْدِهِمْ أي: مِن بَعدِ مَن قَبْلَهم مِن اليهودِ والنَّصارى، وبعبارةٍ أخرى: بَعْدَ مَن تقدَّمَهم أو بعدَ أوائلِهم. وممَّن اختاره: ابنُ أبي زمنين، والعليمي، والشوكاني. يُنظر: ((تفسير ابن أبي زمنين)) (4/164)، ((تفسير العليمي)) (6/179)، ((تفسير الشوكاني)) (4/608). وقيل: معنى مِنْ بَعْدِهِمْ أي: هم المشركون أُورِثوا القرآنَ مِن بَعدِ ما أُورِث أهلُ الكتابِ التَّوارةَ والإنجيلَ. وممَّن اختاره: النسفي، وأبو السعود. يُنظر: ((تفسير النسفي)) (3/249)، ((تفسير أبي السعود)) (8/27).

[384] يُنظر: ((تفسير ابن جرير)) (20/491، 492)، ((تفسير ابن أبي زمنين)) (4/166)، ((تفسير السعدي)) (ص: 757). قال ابن القيِّم: (وهاهنا أمرٌ يَجِبُ التَّنبُّه له، وهو أنَّه لا يُمكِنُ إرادةُ الدُّنيا وعاجِلِها بأعمالِ البِرِّ دونَ الآخِرةِ مع الإيمانِ بالله ورَسولِه ولقائِه، أبدًا؛ فإنَّ الإيمانَ بالله والدَّارِ الآخِرةِ يَستلزِمُ إرادةَ العبدِ لرَحمةِ الله والدَّارِ الآخرةِ بأعمالِه؛ فحيث كان مُرادُه بها الدُّنيا فهذا لا يجامِعُ الإيمانَ أبدًا، وإن جامَعَ الإقرارَ والعِلمَ، فالإيمانُ وراءَ ذلك، والإقرارُ والمعرفةُ حاصِلان لِمَن شَهِدَ اللهُ سُبحانَه له بالكُفرِ مع هذه المعرفةِ، كفِرعَونَ وثمودَ، واليهودِ الَّذين شاهَدوا رسولَ اللهِ وعَرَفوه كما عَرَفوا أبناءَهم وهم مِن أكفَرِ الخَلقِ؛ فإرادةُ الدُّنيا وعاجِلِها بالأعمالِ قد تُجامِعُ هذه المعرفةَ والعِلمَ، ولكِنَّ الإيمانَ الَّذي هو وراءَ ذلك لا بدَّ أن يُريدَ صاحِبُه بأعمالِه اللهَ والدَّارَ الآخِرةَ. واللهُ المُستعانُ). ((عدة الصابرين)) (ص: 167). وقال ابن كثير: (وَمَنْ كَانَ يُرِيدُ حَرْثَ الدُّنْيَا نُؤْتِهِ مِنْهَا وَمَا لَهُ فِي الْآَخِرَةِ مِنْ نَصِيبٍ أيْ: ومَنْ كان إنَّما سَعْيُه لِيَحصُلَ له شَيءٌ مِن الدُّنيا، وليس له إلى الآخرةِ همَّةٌ البتَّةَ بالكلِّيَّةِ؛ حَرَمه اللهُ الآخرةَ، والدُّنيا إنْ شاءَ أعطاه منها، وإنْ لم يَشَأْ لم يَحصُلْ له لا هذه ولا هذه، وفازَ هذا السَّاعي بهذه النِّيَّةِ بالصَّفقةِ الخاسِرةِ في الدُّنيا والآخرةِ. والدَّليلُ على هذا أنَّ هذه الآيةَ هاهنا مُقَيَّدَةٌ بالآيةِ الَّتي في «سُبْحانَ» وهي قولُه تعالَى: مَنْ كَانَ يُرِيدُ الْعَاجِلَةَ عَجَّلْنَا لَهُ فِيهَا مَا نَشَاءُ لِمَنْ نُرِيدُ ثُمَّ جَعَلْنَا لَهُ جَهَنَّمَ يَصْلَاهَا مَذْمُومًا مَدْحُورًا * وَمَنْ أَرَادَ الْآَخِرَةَ وَسَعَى لَهَا سَعْيَهَا وَهُوَ مُؤْمِنٌ فَأُولَئِكَ كَانَ سَعْيُهُمْ مَشْكُورًا * كُلًّا نُمِدُّ هَؤُلَاءِ وَهَؤُلَاءِ مِنْ عَطَاءِ رَبِّكَ وَمَا كَانَ عَطَاءُ رَبِّكَ مَحْظُورًا * انْظُرْ كَيْفَ فَضَّلْنَا بَعْضَهُمْ عَلَى بَعْضٍ وَلَلْآَخِرَةُ أَكْبَرُ دَرَجَاتٍ وَأَكْبَرُ تَفْضِيلًا
[الإسراء: 18-21]
). ((تفسير ابن كثير)) (7/198).

[946] يُنظر: ((تفسير ابن جرير)) (20/542، 543)، ((تفسير ابن كثير)) (7/217)، ((تفسير السعدي)) (ص: 762)، ((أضواء البيان)) للشنقيطي (7/79، 80). قيل: الضَّميرُ في قَولِه تعالى: جَعَلْنَاهُ عائِدٌ إلى الكتابِ، وهو القُرآنُ المذكورُ في قَولِه تعالى: مَا كُنْتَ تَدْرِي مَا الْكِتَابُ وَلَا الْإِيمَانُ، أي: ولكِنْ جعَلْنا الكِتابَ نُورًا. ومِمَّن قال بذلك: ابنُ جرير، والزجاج، وابن عاشور. يُنظر: ((تفسير ابن جرير)) (20/542)، ((معاني القرآن وإعرابه)) للزجاج (4/404)، ((تفسير ابن عاشور)) (25/153). وممَّن قال بهذا القولِ مِن السَّلفِ: السُّدِّيُّ. يُنظر: ((تفسير ابن جرير)) (20/543). وقيل: عائِدٌ إلى الرُّوحِ المذكورِ في قَولِه تعالى: وَكَذَلِكَ أَوْحَيْنَا إِلَيْكَ رُوحًا مِنْ أَمْرِنَا. ومِمَّن ذهب إلى هذا: ابنُ تيميَّة، وابن القيِّم، والشنقيطي. يُنظر: ((المستدرك على مجموع الفتاوى)) لابن تيمية (1/200)، ((اجتماع الجيوش الإسلامية)) لابن القيم (2/87، 88)، ((إغاثة اللهفان من مصايد الشيطان)) لابن القيم (1/21)، ((أضواء البيان)) للشنقيطي (7/79). وقيل: عائِدٌ إلى الإيمانِ المذكورِ في قَولِه تعالى: مَا كُنْتَ تَدْرِي مَا الْكِتَابُ وَلَا الْإِيمَانُ. يُنظر: ((تفسير الماوردي)) (5/213). وممَّن قال بهذا القولِ مِن السَّلفِ: ابنُ عبَّاسٍ. يُنظر: ((تفسير الثعلبي)) (8/326). وقال أبو حيَّان: (يحتمِلُ أن يعودَ إلى قَولِه: رُوحًا، وإلى الْكِتَابُ، وإلى الْإِيمَانُ، وهو أقرَبُ مذكورٍ. وقال ابنُ عطية: عائِدٌ على الكتابِ. انتهى. وقيل: يعودُ إلى الكتابِ والإيمانِ معًا؛ لأنَّ مَقصدَهما واحِدٌ، فهو نظيرُ: وَاللَّهُ وَرَسُولُهُ أَحَقُّ أَنْ يُرْضُوهُ
[التوبة: 62]
). ((تفسير أبي حيان)) (9/352). ويُنظر: ((تفسير ابن عطية)) (5/44).
